    e.preventDefault();
    if (editingId) {
      await api.put(`/savings/${editingId}`, form);
    } else {
      await api.post('/savings', form);
    }
    fetchSavings();
    resetForm();
  };

  const handleEdit = (saving) => {
    setForm(saving);
    setEditingId(saving.id);
  };

  const handleDelete = async (id) => {
    if (window.confirm('Delete this savings account?')) {
      await api.delete(`/savings/${id}`);
      fetchSavings();
    }
  };

  const resetForm = () => {
    setForm({
      account_number: '', member_id: '', savings_type: 'Regular', 
      deposit_amount: '', current_balance: '', opening_date: '', 
      interest_rate: '6', status: 'Active'
    });
    setEditingId(null);
  };

  const filteredSavings = savings.filter(s => 
    s.account_number.toLowerCase().includes(filter.toLowerCase()) ||
    getMemberName(s.member_id).toLowerCase().includes(filter.toLowerCase())
