          </div>
          <div className="form-row">
            <input type="number" step="0.01" placeholder="Initial Deposit" value={form.deposit_amount} onChange={e => setForm({...form, deposit_amount: e.target.value})} />
            <input type="number" step="0.01" placeholder="Current Balance" value={form.current_balance} onChange={e => setForm({...form, current_balance: e.target.value})} />
            <input type="date" placeholder="Opening Date" value={form.opening_date} onChange={e => setForm({...form, opening_date: e.target.value})} />
          </div>
          <div className="form-row">
            <input type="number" step="0.01" placeholder="Interest Rate (%)" value={form.interest_rate} onChange={e => setForm({...form, interest_rate: e.target.value})} />
            <select value={form.status} onChange={e => setForm({...form, status: e.target.value})}>
              <option value="Active">Active</option>
              <option value="Dormant">Dormant</option>
              <option value="Closed">Closed</option>
