        <input type="text" placeholder="Search savings..." value={filter} onChange={e => setFilter(e.target.value)} />
      </div>
      <div className="table-container">
        <table className="data-table">
          <thead>
            <tr>
              <th>Account #</th>
              <th>Member</th>
              <th>Type</th>
              <th>Balance</th>
              <th>Rate</th>
              <th>Status</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {filteredSavings.map(s => (
              <tr key={s.id}>
                <td>{s.account_number}</td>
                <td>{getMemberName(s.member_id)}</td>
                <td>{s.savings_type}</td>
                <td>Rs. {parseFloat(s.current_balance).toLocaleString()}</td>
                <td>{s.interest_rate}%</td>
